import { writeOutput } from "./codegen";

const DOCS_URL = "https://github.com/Pika-Labs/Pika-Skills";
const PLACEHOLDER_VALUE = "dk_PikaDevKeyPlaceholder0000000000000000";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Pika Developer API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pika",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const pikaFirewall = {",
    '  name: "pika",',
    '  description: "Pika",',
    "  placeholders: {",
    `    PIKA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://srkibaanghvsriahb.pika.art",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "DevKey ${{ secrets.PIKA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://7i30hpv4bo9ud5mhianq.pika.art",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "DevKey ${{ secrets.PIKA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Pika firewall config...");
  const ts = generateTypeScript();
  writeOutput("pika", ts, import.meta.dirname);
}
